challenges.description:
Translate the HLSL snippet below to GLSL ES 3.0. Replace every type name and every function call with its GLSL equivalent, then wire the result into fragColor.

HLSL reference:
```hlsl
float3 a = float3(1.0, 0.0, 0.0);
float3 b = float3(0.0, 0.0, 1.0);
float3 c = lerp(a, b, 0.5);
// output c as RGB, alpha = 1.0
```

challenges.template:
out vec4 fragColor;

void main() {
    // Translate the HLSL above to GLSL
    /* ??? */
    fragColor = vec4(c, 1.0);
}

challenges.solution:
out vec4 fragColor;

void main() {
    vec3 a = vec3(1.0, 0.0, 0.0);
    vec3 b = vec3(0.0, 0.0, 1.0);
    vec3 c = mix(a, b, 0.5);
    fragColor = vec4(c, 1.0);
}

hlsl.code:
float4 main() : SV_Target {
    float3 a = float3(1.0, 0.0, 0.0);
    float3 b = float3(0.0, 0.0, 1.0);
    float3 c = lerp(a, b, 0.5);
    return float4(c, 1.0);
}

