challenges.description:
The snippet below is broken HLSL-inside-GLSL — someone copied HLSL types and functions into a GLSL file. Fix every type name and function name so it compiles as valid GLSL ES 3.0. Use u_time and u_resolution.

Broken code to fix:
```
uniform float2 u_resolution;  // wrong type name
uniform float  u_time;
out float4 fragColor;          // wrong type name

void main() {
    float2 uv = gl_FragCoord.xy / u_resolution;  // wrong type name
    float3 col = lerp(                             // wrong function
        float3(0.2, 0.4, 0.9),                    // wrong type name
        float3(0.9, 0.3, 0.1),                    // wrong type name
        uv.x + 0.3 * sin(u_time)
    );
    fragColor = float4(col, 1.0);                 // wrong type name
}
```

challenges.template:
uniform vec2 u_resolution;
uniform float u_time;
out vec4 fragColor;

void main() {
    // Fix the broken lines below (type names and function names)
    vec2 uv = gl_FragCoord.xy / u_resolution;
    vec3 col = /* ??? */(
        /* ??? */,
        /* ??? */,
        uv.x + 0.3 * sin(u_time)
    );
    fragColor = vec4(col, 1.0);
}

challenges.solution:
uniform vec2 u_resolution;
uniform float u_time;
out vec4 fragColor;

void main() {
    vec2 uv = gl_FragCoord.xy / u_resolution;
    vec3 col = mix(
        vec3(0.2, 0.4, 0.9),
        vec3(0.9, 0.3, 0.1),
        uv.x + 0.3 * sin(u_time)
    );
    fragColor = vec4(col, 1.0);
}

hlsl.code:
cbuffer Uniforms : register(b0) {
    float2 u_resolution;
    float  u_time;
};

float4 main() : SV_Target {
    float2 uv = float2(0.5, 0.5); // no gl_FragCoord in simple HLSL example
    float3 col = lerp(
        float3(0.2, 0.4, 0.9),
        float3(0.9, 0.3, 0.1),
        uv.x + 0.3 * sin(u_time)
    );
    return float4(col, 1.0);
}

slang.code:
uniform float2 u_resolution;
uniform float  u_time;

[shader("fragment")]
float4 main(float4 pos : SV_Position) : SV_Target {
    float2 uv = pos.xy / u_resolution;
    float3 col = lerp(
        float3(0.2, 0.4, 0.9),
        float3(0.9, 0.3, 0.1),
        uv.x + 0.3 * sin(u_time)
    );
    return float4(col, 1.0);
}
